evaluators.evaluation_logic:
const checkpoints = [];
const courses = JSON.parse(localStorage.getItem('courses') || '[]');
const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Determine qualifying beginner leadership courses under $100 with rating >= 4.0
let qualifyingCourses = courses.filter(c => {
  if (!c || c.status !== 'active') return false;
  if (c.level !== 'beginner') return false;
  if (typeof c.price !== 'number' || c.price > 100) return false;
  if (typeof c.rating !== 'number' || c.rating < 4.0) return false;
  const topics = Array.isArray(c.topics) ? c.topics : [];
  return topics.includes('leadership');
});

qualifyingCourses.sort((a, b) => (a.price || 0) - (b.price || 0));
const cheapestTwo = qualifyingCourses.slice(0, 2);

let qualifyingInCartCount = 0;
if (cart && cart.id && Array.isArray(cartItems)) {
  const itemsForCart = cartItems.filter(ci => ci.cart_id === cart.id && ci.item_type === 'course' && (ci.quantity || 0) > 0);
  const idsInCart = new Set(itemsForCart.map(ci => ci.item_ref_id));
  cheapestTwo.forEach(c => {
    if (c && idsInCart.has(c.id)) {
      qualifyingInCartCount++;
    }
  });
}

// CP1 (0.4): At least the single cheapest qualifying course is in the cart
checkpoints.push({ passed: cheapestTwo.length >= 1 && qualifyingInCartCount >= 1, weight: 0.4 });
// CP2 (0.6): Both cheapest qualifying courses are in the cart
checkpoints.push({ passed: cheapestTwo.length >= 2 && qualifyingInCartCount >= 2, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const packages = JSON.parse(localStorage.getItem('consulting_packages') || '[]');
const requests = JSON.parse(localStorage.getItem('proposal_requests') || '[]');

// Qualifying packages: small business, active, >=10 hours/month, < $1200/month
const qualifyingPackages = packages.filter(p => {
  if (!p || p.status !== 'active') return false;
  if (p.audience !== 'small_business_1_50') return false;
  if (typeof p.hours_per_month !== 'number' || p.hours_per_month < 10) return false;
  if (typeof p.monthly_price !== 'number' || p.monthly_price >= 1200) return false;
  return true;
});

let selectedRequest = null;
let selectedPackage = null;
if (Array.isArray(requests) && requests.length > 0 && qualifyingPackages.length > 0) {
  const validRequests = requests.filter(r => r && r.source_type === 'consulting_package' && r.consulting_package_id);
  validRequests.sort((a, b) => {
    const da = a.created_at ? Date.parse(a.created_at) : 0;
    const db = b.created_at ? Date.parse(b.created_at) : 0;
    return db - da;
  });
  if (validRequests.length > 0) {
    selectedRequest = validRequests[0];
    selectedPackage = packages.find(p => p.id === selectedRequest.consulting_package_id) || null;
  }
}

const packageQualifies = !!selectedPackage && qualifyingPackages.some(p => p.id === selectedPackage.id);

let cheapestQualifying = null;
if (qualifyingPackages.length > 0) {
  cheapestQualifying = [...qualifyingPackages].sort((a, b) => (a.monthly_price || 0) - (b.monthly_price || 0))[0];
}

const isCheapest = !!selectedPackage && !!cheapestQualifying && selectedPackage.id === cheapestQualifying.id;

// CP1 (0.4): Latest consulting-package proposal is for a qualifying small-business package
checkpoints.push({ passed: packageQualifies, weight: 0.4 });
// CP2 (0.6): That package is the cheapest among all qualifying options
checkpoints.push({ passed: packageQualifies && isCheapest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const workshops = JSON.parse(localStorage.getItem('workshops') || '[]');
const trainingPlan = JSON.parse(localStorage.getItem('training_plan') || 'null');
const trainingPlanItems = JSON.parse(localStorage.getItem('training_plan_items') || '[]');

// Qualifying workshops: active, in-person, 1_day or 2_day, category includes leadership or change_management
let qualifying = workshops.filter(w => {
  if (!w || w.status !== 'active') return false;
  if (w.format !== 'in_person') return false;
  if (!['1_day', '2_day'].includes(w.duration_type)) return false;
  const cats = Array.isArray(w.categories) ? w.categories : [];
  return cats.includes('leadership') || cats.includes('change_management');
});

qualifying.sort((a, b) => (b.rating || 0) - (a.rating || 0));
const top3 = qualifying.slice(0, 3);
const top3Ids = top3.map(w => w.id);

let countInPlan = 0;
if (trainingPlan && trainingPlan.id && Array.isArray(trainingPlanItems)) {
  const itemsForPlan = trainingPlanItems.filter(i => i.training_plan_id === trainingPlan.id);
  const idsInPlan = new Set(itemsForPlan.map(i => i.workshop_id));
  top3Ids.forEach(id => {
    if (idsInPlan.has(id)) {
      countInPlan++;
    }
  });
}

// CP1 (0.3): Training plan includes at least the highest-rated qualifying workshop
checkpoints.push({ passed: top3Ids.length >= 1 && countInPlan >= 1, weight: 0.3 });
// CP2 (0.3): Training plan includes at least the top two qualifying workshops
checkpoints.push({ passed: top3Ids.length >= 2 && countInPlan >= 2, weight: 0.3 });
// CP3 (0.4): Training plan includes all top three qualifying workshops
checkpoints.push({ passed: top3Ids.length >= 3 && countInPlan >= 3, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const services = JSON.parse(localStorage.getItem('services') || '[]');
const slots = JSON.parse(localStorage.getItem('availability_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

// Find an active coaching session service
const coachingService = services.find(s => s && s.service_type === 'coaching_session' && s.is_active);

let baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : null;
let weekStart = null;
let weekEnd = null;
if (baselineDateStr) {
  const base = new Date(baselineDateStr + 'T00:00:00Z');
  if (!isNaN(base.getTime())) {
    const dayOfWeek = base.getUTCDay(); // 0=Sun..6=Sat
    const daysUntilNextMonday = ((1 - dayOfWeek + 7) % 7) || 7; // at least 1, at most 7
    const nextMonday = new Date(base.getTime());
    nextMonday.setUTCDate(nextMonday.getUTCDate() + daysUntilNextMonday);
    weekStart = new Date(Date.UTC(nextMonday.getUTCFullYear(), nextMonday.getUTCMonth(), nextMonday.getUTCDate()));
    weekEnd = new Date(weekStart.getTime());
    weekEnd.setUTCDate(weekEnd.getUTCDate() + 7);
  }
}

let candidateSlots = [];
if (coachingService && weekStart && weekEnd && Array.isArray(slots)) {
  candidateSlots = slots.filter(s => {
    if (!s || s.service_id !== coachingService.id) return false;
    if (s.time_of_day !== 'morning') return false;
    if (s.is_booked) return false; // available-only for "earliest available" logic
    const start = new Date(s.start_datetime);
    if (isNaN(start.getTime())) return false;
    if (start < weekStart || start >= weekEnd) return false;
    const hour = start.getUTCHours();
    if (hour < 9 || hour >= 12) return false; // 09:00-12:00 window
    return true;
  });
}

candidateSlots.sort((a, b) => {
  const sa = new Date(a.start_datetime).getTime();
  const sb = new Date(b.start_datetime).getTime();
  return sa - sb;
});
const earliestAvailableSlot = candidateSlots[0] || null;

// Find bookings that are 60-minute coaching sessions in the target next-week morning window
let qualifyingBookings = [];
if (coachingService && weekStart && weekEnd && Array.isArray(bookings)) {
  qualifyingBookings = bookings.filter(b => {
    if (!b || b.service_id !== coachingService.id) return false;
    if (b.status && b.status !== 'confirmed') return false;
    if (b.duration_minutes !== 60) return false;
    const start = new Date(b.start_datetime);
    if (isNaN(start.getTime())) return false;
    if (start < weekStart || start >= weekEnd) return false;
    const slot = slots.find(s => s.id === b.slot_id);
    if (!slot || slot.time_of_day !== 'morning') return false;
    const hour = start.getUTCHours();
    if (hour < 9 || hour >= 12) return false;
    return true;
  });
}

qualifyingBookings.sort((a, b) => {
  const sa = new Date(a.start_datetime).getTime();
  const sb = new Date(b.start_datetime).getTime();
  return sa - sb;
});
const earliestBooked = qualifyingBookings[0] || null;

// CP1 (0.4): User booked any 60-minute coaching session in the correct next-week morning window
checkpoints.push({ passed: !!earliestBooked, weight: 0.4 });
// CP2 (0.6): That booking is for the earliest available qualifying slot
checkpoints.push({ passed: !!earliestBooked && !!earliestAvailableSlot && earliestBooked.slot_id === earliestAvailableSlot.id, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const caseStudies = JSON.parse(localStorage.getItem('case_studies') || '[]');
const savedItems = JSON.parse(localStorage.getItem('saved_items') || '[]');

// Qualifying case studies: technology, published, budget > 20000, duration_bucket 'less_than_6_months'
const qualifyingIds = caseStudies.filter(c => {
  if (!c || c.status !== 'published') return false;
  if (c.industry !== 'technology') return false;
  if (typeof c.budget !== 'number' || c.budget <= 20000) return false;
  if (c.duration_bucket !== 'less_than_6_months') return false;
  return true;
}).map(c => c.id);

const qualifyingSaved = savedItems.filter(s => s && s.content_type === 'case_study' && qualifyingIds.includes(s.content_id));
const count = qualifyingSaved.length;

// CP1 (0.2): At least one qualifying technology case study saved
checkpoints.push({ passed: count >= 1, weight: 0.2 });
// CP2 (0.3): At least two qualifying technology case studies saved
checkpoints.push({ passed: count >= 2, weight: 0.3 });
// CP3 (0.5): At least three qualifying technology case studies saved
checkpoints.push({ passed: count >= 3, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const subscriptions = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

// Find remote-teams articles (tag includes 'remote_teams') and sort by popularity descending
let remoteArticles = articles.filter(a => {
  if (!a || a.status !== 'published') return false;
  const tags = Array.isArray(a.tags) ? a.tags : [];
  return tags.includes('remote_teams');
});

remoteArticles.sort((a, b) => (b.popularity_score || b.views || 0) - (a.popularity_score || a.views || 0));
const thirdArticle = remoteArticles[2] || null;

// Subscriptions that are weekly and include both 'remote_leadership' and 'team_productivity'
const qualifyingSubs = subscriptions.filter(s => {
  if (!s || s.frequency !== 'weekly') return false;
  const topics = Array.isArray(s.topics) ? s.topics : [];
  const hasRemoteLeadership = topics.includes('remote_leadership');
  const hasTeamProductivity = topics.includes('team_productivity');
  return hasRemoteLeadership && hasTeamProductivity;
});

const qualifyingSubsOnThird = qualifyingSubs.filter(s => thirdArticle && s.article_id === thirdArticle.id);

// CP1 (0.4): At least one weekly subscription with both remote_leadership and team_productivity topics
checkpoints.push({ passed: qualifyingSubs.length > 0, weight: 0.4 });
// CP2 (0.6): Such a subscription originated from the 3rd most popular remote-teams article
checkpoints.push({ passed: qualifyingSubsOnThird.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const configs = JSON.parse(localStorage.getItem('custom_training_configurations') || '[]');
const proposals = JSON.parse(localStorage.getItem('proposal_requests') || '[]');
// settings are stored but not strictly required for evaluation since estimate is already on config

const config = Array.isArray(configs) && configs.length > 0 ? configs[0] : null;

let configuredOk = false;
if (config) {
  const isOnSite = config.delivery_format === 'on_site_at_office' || config.delivery_format === 'in_house_training';
  const has2Days = config.workshop_length_days === 2;
  const has25Participants = config.num_participants === 25;
  const hasCoaching = !!config.include_followup_group_coaching && (config.followup_group_coaching_sessions || 0) > 0;
  const noPrework = !config.include_online_prework_modules;
  const underBudget = typeof config.estimated_total === 'number' && config.estimated_total < 8000;
  configuredOk = isOnSite && has2Days && has25Participants && hasCoaching && noPrework && underBudget;
}

const hasProposal = !!config && Array.isArray(proposals) && proposals.some(p => {
  return p && p.source_type === 'custom_training_configuration' && p.custom_training_configuration_id === config.id && p.status === 'submitted';
});

// CP1 (0.4): Configuration matches on-site, 2-day, 25 participants, includes follow-up coaching, excludes prework, and is under $8,000
checkpoints.push({ passed: configuredOk, weight: 0.4 });
// CP2 (0.6): A submitted proposal request references this qualifying configuration
checkpoints.push({ passed: configuredOk && hasProposal, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];
const consultants = JSON.parse(localStorage.getItem('consultants') || '[]');
const contactRequests = JSON.parse(localStorage.getItem('consultant_contact_requests') || '[]');

// Qualifying consultants: active, North America, expertise includes leadership_development, >=10 years, >=5 clients
const qualifyingConsultants = consultants.filter(c => {
  if (!c || c.status !== 'active') return false;
  if (c.region !== 'north_america') return false;
  const expertise = Array.isArray(c.expertise_areas) ? c.expertise_areas : [];
  if (!expertise.includes('leadership_development')) return false;
  if (typeof c.years_experience !== 'number' || c.years_experience < 10) return false;
  const clientLogosCount = Array.isArray(c.client_logos) ? c.client_logos.length : 0;
  const clientNamesCount = Array.isArray(c.client_names) ? c.client_names.length : 0;
  const clientCount = Math.max(clientLogosCount, clientNamesCount);
  if (clientCount < 5) return false;
  return true;
});

const qualifyingIds = qualifyingConsultants.map(c => c.id);

const qualifyingRequests = contactRequests.filter(r => r && qualifyingIds.includes(r.consultant_id));

const mostExperienced = qualifyingConsultants.slice().sort((a, b) => (b.years_experience || 0) - (a.years_experience || 0))[0] || null;
const requestsToMostExperienced = qualifyingRequests.filter(r => mostExperienced && r.consultant_id === mostExperienced.id);

// CP1 (0.6): At least one contact request targets a qualifying North America leadership-development consultant with >=10 years and >=5 clients
checkpoints.push({ passed: qualifyingRequests.length > 0, weight: 0.6 });
// CP2 (0.4): At least one such request targets the most experienced qualifying consultant
checkpoints.push({ passed: requestsToMostExperienced.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
